import { useState, useEffect, useRef } from 'react'
import { Link, useLocation } from 'react-router-dom'
import AuraLogo from '@/components/AuraLogo'

const T = {
  bg: '#0B0F14', surface: '#0F1620', surface2: '#111A24',
  border: '#1F2A37', textPrimary: '#E5E7DB', textSecondary: '#90A3AF',
  blue: '#60A5FA', green: '#22C55E', purple: '#A78BFA',
  monoFont: "'JetBrains Mono', monospace",
  bodyFont: "'Plus Jakarta Sans', -apple-system, sans-serif",
}

const NAV_LINKS = [
  { label: 'Platform', path: '/platform' },
  { label: 'Download', path: '/download', highlight: true },
  { label: 'Strategies', path: '/strategies-public' },
  { label: 'Pricing', path: '/pricing-plans' },
  { label: 'Fund Mode', path: '/fund-mode' },
  {
    label: 'Compare', path: '/compare',
    children: [
      { label: 'vs Trade Ideas', path: '/compare/trade-ideas' },
      { label: 'vs TrendSpider', path: '/compare/trendspider' },
      { label: 'vs TradingView', path: '/compare/tradingview' },
      { label: 'vs QuantConnect', path: '/compare/quantconnect' },
      { label: 'vs Robinhood', path: '/compare/robinhood' },
      { label: 'vs Composer', path: '/compare/composer' },
      { label: 'vs 3Commas', path: '/compare/3commas' },
    ],
  },
  {
    label: 'Resources', path: null,
    children: [
      { label: 'Supported Brokers', path: '/brokers' },
      { label: 'Get All Apps', path: '/apps' },
      { label: 'Desktop App', path: '/desktop' },
      { label: 'Mobile App', path: '/mobile' },
      { label: 'Strategy Lab', path: '/strategy-lab-public' },
      { label: 'Risk Engine', path: '/risk-engine' },
      { label: 'Execution', path: '/execution' },
      { label: 'FAQ', path: '/faq' },
      { label: 'Security', path: '/security' },
      { label: 'Documentation', path: '/docs' },
      { label: 'Changelog', path: '/changelog' },
    ],
  },
]

function Dropdown({ items, onClose }) {
  const ref = useRef(null)
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) onClose() }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [onClose])

  return (
    <div ref={ref} style={{
      position: 'absolute', top: '100%', left: '50%', transform: 'translateX(-50%)',
      marginTop: 8, background: T.surface, border: `1px solid ${T.border}`,
      borderRadius: 10, padding: '6px 0', minWidth: 180, zIndex: 1001,
      boxShadow: '0 8px 32px rgba(0,0,0,0.4)', backdropFilter: 'blur(16px)',
    }}>
      {items.map(item => (
        <Link key={item.path} to={item.path} onClick={onClose} style={{
          display: 'block', padding: '8px 16px', fontSize: 13, fontWeight: 500,
          color: T.textSecondary, textDecoration: 'none', transition: 'all 0.15s ease',
        }}
        onMouseEnter={e => { e.target.style.color = T.textPrimary; e.target.style.background = T.surface2; }}
        onMouseLeave={e => { e.target.style.color = T.textSecondary; e.target.style.background = 'transparent'; }}
        >{item.label}</Link>
      ))}
    </div>
  )
}

export default function PublicNav() {
  const location = useLocation()
  const [scrolled, setScrolled] = useState(false)
  const [mobileOpen, setMobileOpen] = useState(false)
  const [openDropdown, setOpenDropdown] = useState(null)

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20)
    window.addEventListener('scroll', onScroll)
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  useEffect(() => { setMobileOpen(false); setOpenDropdown(null) }, [location.pathname])

  return (
    <>
      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '0 32px', height: 64,
        background: scrolled ? 'rgba(13,17,23,0.95)' : 'rgba(13,17,23,0.7)',
        backdropFilter: 'blur(16px)',
        borderBottom: `1px solid ${scrolled ? T.border : 'transparent'}`,
        transition: 'all 0.25s ease',
        fontFamily: T.bodyFont,
      }}>
        {/* Logo */}
        <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center' }}>
          <AuraLogo variant="header" height={46} glow />
        </Link>

        {/* Desktop links */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          {NAV_LINKS.map(l => {
            const active = l.path && location.pathname.startsWith(l.path)
            const hasChildren = l.children && l.children.length > 0
            const isOpen = openDropdown === l.label

            return (
              <div key={l.label} style={{ position: 'relative' }}
                onMouseEnter={() => { if (hasChildren) setOpenDropdown(l.label) }}
                onMouseLeave={() => { if (hasChildren) setOpenDropdown(null) }}
              >
                {l.path ? (
                  <Link to={l.path} style={{
                    fontSize: 13, fontWeight: l.highlight ? 600 : 500,
                    color: l.highlight ? '#fff' : active ? T.textPrimary : T.textSecondary,
                    textDecoration: 'none', padding: l.highlight ? '8px 16px' : '8px 14px', borderRadius: 10,
                    background: l.highlight ? 'linear-gradient(135deg, #60A5FA 0%, #3B82F6 100%)' : active ? T.surface2 : 'transparent',
                    transition: 'all 0.15s ease',
                    display: 'flex', alignItems: 'center', gap: 6,
                    boxShadow: l.highlight ? '0 0 12px rgba(96,165,250,0.25)' : 'none',
                  }}
                  onMouseEnter={e => { if (l.highlight) { e.currentTarget.style.opacity = '0.9'; } else if (!active) { e.currentTarget.style.color = T.textPrimary; e.currentTarget.style.background = T.surface2; }}}
                  onMouseLeave={e => { if (l.highlight) { e.currentTarget.style.opacity = '1'; } else if (!active) { e.currentTarget.style.color = T.textSecondary; e.currentTarget.style.background = 'transparent'; }}}
                  >
                    {l.highlight && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>}
                    {l.label}
                    {hasChildren && <span style={{ fontSize: 10, opacity: 0.6 }}>&#9662;</span>}
                  </Link>
                ) : (
                  <button onClick={() => setOpenDropdown(isOpen ? null : l.label)} style={{
                    fontSize: 13, fontWeight: 500, color: T.textSecondary,
                    background: 'transparent', border: 'none', cursor: 'pointer',
                    padding: '8px 14px', borderRadius: 10, transition: 'all 0.15s ease',
                    display: 'flex', alignItems: 'center', gap: 4, fontFamily: T.bodyFont,
                  }}
                  onMouseEnter={e => { e.currentTarget.style.color = T.textPrimary; e.currentTarget.style.background = T.surface2; }}
                  onMouseLeave={e => { e.currentTarget.style.color = T.textSecondary; e.currentTarget.style.background = 'transparent'; }}
                  >
                    {l.label}
                    <span style={{ fontSize: 10, opacity: 0.6 }}>&#9662;</span>
                  </button>
                )}
                {hasChildren && isOpen && (
                  <Dropdown items={l.children} onClose={() => setOpenDropdown(null)} />
                )}
              </div>
            )
          })}

          <div style={{ width: 1, height: 20, background: T.border, margin: '0 8px' }} />

          <Link to="/login" style={{
            fontSize: 13, fontWeight: 500, color: T.textSecondary,
            textDecoration: 'none', padding: '8px 14px', borderRadius: 10,
            transition: 'all 0.15s ease',
          }}
          onMouseEnter={e => { e.target.style.color = T.textPrimary; }}
          onMouseLeave={e => { e.target.style.color = T.textSecondary; }}
          >Sign In</Link>

          <Link to="/register" style={{
            fontSize: 13, fontWeight: 600, color: '#fff',
            textDecoration: 'none', padding: '8px 18px', borderRadius: 10,
            background: 'linear-gradient(135deg, #60A5FA 0%, #A78BFA 100%)',
            transition: 'opacity 0.15s ease',
          }}
          onMouseEnter={e => { e.target.style.opacity = '0.85'; }}
          onMouseLeave={e => { e.target.style.opacity = '1'; }}
          >Get Started</Link>
        </div>

        {/* Mobile hamburger */}
        <button onClick={() => setMobileOpen(!mobileOpen)} style={{
          display: 'none', background: 'none', border: 'none', cursor: 'pointer',
          color: T.textPrimary, fontSize: 22, padding: 8,
        }}>
          {mobileOpen ? '\u2715' : '\u2630'}
        </button>
      </nav>

      {/* Mobile menu */}
      {mobileOpen && (
        <div style={{
          position: 'fixed', top: 64, left: 0, right: 0, bottom: 0, zIndex: 999,
          background: 'rgba(11,15,20,0.98)', backdropFilter: 'blur(16px)',
          padding: '24px 32px', overflowY: 'auto', fontFamily: T.bodyFont,
        }}>
          {NAV_LINKS.map(l => (
            <div key={l.label} style={{ marginBottom: 8 }}>
              {l.path ? (
                <Link to={l.path} onClick={() => setMobileOpen(false)} style={{
                  display: l.highlight ? 'flex' : 'block', alignItems: 'center', gap: 8,
                  padding: '12px 0', fontSize: 16, fontWeight: 600,
                  color: l.highlight ? T.blue : T.textPrimary, textDecoration: 'none',
                  borderBottom: `1px solid ${T.border}`,
                }}>
                  {l.highlight && <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>}
                  {l.label}
                </Link>
              ) : (
                <div style={{ padding: '12px 0', fontSize: 16, fontWeight: 600,
                  color: T.textPrimary, borderBottom: `1px solid ${T.border}` }}>{l.label}</div>
              )}
              {l.children && l.children.map(c => (
                <Link key={c.path} to={c.path} onClick={() => setMobileOpen(false)} style={{
                  display: 'block', padding: '10px 0 10px 16px', fontSize: 14,
                  color: T.textSecondary, textDecoration: 'none',
                }}>{c.label}</Link>
              ))}
            </div>
          ))}
          <div style={{ marginTop: 24, display: 'flex', flexDirection: 'column', gap: 12 }}>
            <Link to="/login" onClick={() => setMobileOpen(false)} style={{
              display: 'block', textAlign: 'center', padding: '12px 0', fontSize: 14,
              fontWeight: 500, color: T.textSecondary, textDecoration: 'none',
              border: `1px solid ${T.border}`, borderRadius: 10,
            }}>Sign In</Link>
            <Link to="/register" onClick={() => setMobileOpen(false)} style={{
              display: 'block', textAlign: 'center', padding: '12px 0', fontSize: 14,
              fontWeight: 600, color: '#fff', textDecoration: 'none', borderRadius: 10,
              background: 'linear-gradient(135deg, #60A5FA 0%, #A78BFA 100%)',
            }}>Get Started</Link>
          </div>
        </div>
      )}

      {/* Spacer */}
      <div style={{ height: 64 }} />

      {/* Mobile breakpoint styles */}
      <style>{`
        @media (max-width: 768px) {
          nav > div:nth-child(2) { display: none !important; }
          nav > button { display: block !important; }
        }
      `}</style>
    </>
  )
}
